mapper.select:
SELECT nursing_id, visit_id, recorded_at, systolic_bp, diastolic_bp, pulse, respiration, temperature, spo2, observation, pain_score, consciousness_level, initial_assessment, status, created_at, updated_at FROM nursing_record WHERE status = 'ACTIVE'
AND visit_id = #{searchValue}
AND TO_CHAR(recorded_at, 'YYYY-MM-DD') = #{searchValue}
ORDER BY created_at DESC
